  ('aboriginal-c5fb3965-moex-00320', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於國家賠償責任之成立，下列敘述何者正確？', '["如為檢察官所為，應就其追訴案件犯職務上之罪，經判決有罪確定", "如為受委託行使公權力團體所為，必須公務員就其指揮監督有故意或過失", "如為怠於執行職務之行為，僅限於公務員有故意或重大過失之情形", "公務員係指依法令服務於國家、地方自治團體所屬機關而具有法定職務權限者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00321', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依國家賠償法規定，關於公共設施設置管理有欠缺之國家賠償責任，下列敘述何者正確？', '["採無過失責任", "採故意或重大過失責任", "採具體輕過失責任", "採抽象輕過失責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00322', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於行政法院管轄權之敘述，下列何者錯誤？', '["以行政機關為被告起訴，原則上由該機關所在地之行政法院管轄", "以公司為被告起訴，由該公司之主事務所或主營業所所在地之行政法院管轄", "以一般人民為被告起訴，由被告住所地之行政法院管轄", "因不動產徵收涉訟者，專屬作成徵收處分機關所在地之行政法院管轄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00323', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '行政訴訟上之交通裁決事件，其起訴之裁判費，按件徵收新臺幣多少元？', '["4,000元", "2,000元", "750元", "300元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00324', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於行政訴訟程序之敘述，下列何者錯誤？', '["高等行政法院之第一審判決，應本於言詞辯論而為之", "行政法院之裁定，得不經言詞辯論而為之", "最高行政法院之判決，原則上不經言詞辯論而為之", "交通裁決事件之裁判，應經言詞辯論而為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00325', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依行政訴訟法規定，下列何者非屬提起撤銷訴訟之程序要件？', '["原告原則上須經訴願而不服訴願結果", "原告須對現存有效之行政處分提起", "原告須於法定之不變期間內提起訴訟", "原告須釋明其有即受法院判決確認之利益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00326', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '就特定訴訟繫屬之事件，如行政法院認為其對該事件欠缺審判權，並將其移送至審理民事訴訟事件之 普通法院，而普通法院亦認其無審判權時，下列敘述何者正確？', '["普通法院應直接駁回該訴訟", "普通法院應再依職權將該事件移送至行政法院", "得依一造當事人之聲請，直接由普通法院審判", "如當事人未合意由普通法院審判，應停止訴訟程序，並聲請司法院大法官解釋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00327', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '甲男、乙女同居於共同之住所，甲以乙為被告，向法院訴請返還借款。關於此訴訟之文書送達，下列 敘述何者正確？', '["送達人若於住所外之他處會晤甲、乙時，得於會晤處所送達", "送達於住所而不獲會晤甲時，得將文書付與乙", "得逕將文書寄存於送達地之自治或警察機關，即生效力", "寄存送達，自寄存之次日起，發生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
